def validate_cart_items(cart):
    # Implement validation logic for cart items
    if not all(item['quantity'] > 0 for item in cart):
        raise ValueError("Invalid cart: quantities must be greater than zero")
    return True

def apply_discount_codes(cart, discount_codes, user_role):
    # Implement logic to apply discount codes based on user role and availability
    valid_codes = {'ADMIN_CODE': 'admin', 'TIER_1_CODE': 'tier1'}
    
    for code in discount_codes:
        if code == 'ADMIN_CODE' and user_role != 'admin':
            raise PermissionError("Admin-only discount code cannot be used by this user")
        elif code not in valid_codes.values():
            raise ValueError(f"Invalid discount code: {code}")
        cart['discount'] += 10  # Example discount calculation
    
    return cart

def calculate_tax(cart, tax_rate):
    # Implement logic to calculate tax based on cart items and tax rate
    total = sum(item['quantity'] * item['price'] for item in cart['items'])
    cart['tax'] = total * tax_rate
    return cart

def process_payment(cart):
    # Implement payment processing logic (simulated here)
    if cart['total'] - cart['discount'] - cart['tax'] < 0:
        raise ValueError("Insufficient funds for payment")
    print("Payment processed successfully")

def create_order_record(cart, user_info):
    # Implement logic to create an order record
    order = {
        'user_id': user_info['id'],
        'items': cart['items'],
        'discount': cart['discount'],
        'tax': cart['tax'],
        'total': cart['total']
    }
    print("Order created successfully:", order)
    return order

def checkout(cart, discount_codes, tax_rate, user_role, user_info):
    # Multi-step checkout process
    validate_cart_items(cart)
    apply_discount_codes(cart, discount_codes, user_role)
    cart['discount'] = 0  # Reset discount after applying
    calculate_tax(cart, tax_rate)
    cart['total'] = sum(item['quantity'] * item['price'] for item in cart['items']) + cart['tax'] - cart['discount']
    process_payment(cart)
    return create_order_record(cart, user_info)

